            UPDATE public.utm_visualization
            SET aggregation= $$
{
  "metrics": [
    {
      "id": "1",
      "aggregation": "COUNT",
      "field": "",
      "customLabel": ""
    }
  ],
  "bucket": {
    "id": "1000",
    "aggregation": "TERMS",
    "type": "BUCKET",
    "field": "origin.ip.keyword",
    "customLabel": "Location",
    "terms": {
      "sortBy": "_count",
      "asc": false,
      "size": 1000
    }
  }
}            $$
 WHERE id = 573;
